116	export function generateDateDisplay(dateStart: Date | null, dateEnd: Date | null): string {
117	  if (!dateStart) return "";
118	
119	  const italianMonths = ["gennaio", "febbraio", "marzo", "aprile", "maggio", "giugno",
120	    "luglio", "agosto", "settembre", "ottobre", "novembre", "dicembre"];
121	
122	  const day1 = dateStart.getDate();
123	  const month1 = italianMonths[dateStart.getMonth()];
124	  const year1 = dateStart.getFullYear();
125	
126	  if (!dateEnd) {
127	    const time = dateStart.getHours() > 0 ? ` alle ${dateStart.getHours().toString().padStart(2, "0")}:${dateStart.getMinutes().toString().padStart(2, "0")}` : "";
128	    return `${day1} ${month1} ${year1}${time}`;
129	  }
130	
131	  const day2 = dateEnd.getDate();
132	  const month2 = italianMonths[dateEnd.getMonth()];
133	  const year2 = dateEnd.getFullYear();
134	
135	  if (dateStart.getMonth() === dateEnd.getMonth() && dateStart.getFullYear() === dateEnd.getFullYear()) {
136	    return `${day1}–${day2} ${month1} ${year1}`;
137	  }
138	  return `${day1} ${month1} – ${day2} ${month2} ${year1}`;
139	}
